mapper.update:
update orders
set order_no = #{orderNo}
where order_seq = #{orderSeq}

mapper.select:
select o.order_seq as orderSeq, o.order_no as orderNo, o.seller_seq as sellerSeq, o.buyer_seq as buyerSeq, o.status as status, o.created_at as createdAt, o.total_amount as totalAmount, st.company_name as companyName,
concat( min(oi.item_name), CASE WHEN COUNT(oi.order_item_seq) > 1 THEN CONCAT(' 외 ', COUNT(oi.order_item_seq) - 1, '건') ELSE '' END ) AS itemSummary
from orders o join stores st on o.seller_seq = st.store_seq join order_items oi on o.order_seq = oi.order_seq
where o.buyer_seq = #{storeSeq}
and ( o.order_no like concat('%', #{keyword}, '%') or st.company_name like concat('%', #{keyword}, '%') or oi.item_name like concat('%', #{keyword}, '%') )
and o.status = #{status}
and DATE(o.created_at) >= #{startDate}
and DATE(o.created_at) <= #{endDate}
group by o.order_seq, o.order_no, o.seller_seq, o.buyer_seq, o.status, o.created_at, o.total_amount, st.company_name
order by o.order_seq desc

mapper.update:
UPDATE orders
SET status = #{status}
WHERE order_seq = #{orderSeq}

mapper.select:
SELECT buyer_seq
FROM orders
WHERE order_seq = #{orderSeq}
